import java.util.*;

public class HuffmanRatio {

    static class Node {
        char ch; int freq; Node left, right;
        Node(char c,int f){ch=c;freq=f;}
        Node(int f,Node l,Node r){ch='\0';freq=f;left=l;right=r;}
    }

    void buildMap(Node r, String c, Map<Character,String> m) {
        if(r==null)return;
        if(r.left==null&&r.right==null){m.put(r.ch,c);return;}
        buildMap(r.left,c+"0",m);buildMap(r.right,c+"1",m);
    }

    public void analyze(char[] chars, int[] freqs) {
        PriorityQueue<Node> pq=new PriorityQueue<>(Comparator.comparingInt(n->n.freq));
        for(int i=0;i<chars.length;i++) pq.add(new Node(chars[i],freqs[i]));
        while(pq.size()>1){Node a=pq.poll(),b=pq.poll();pq.add(new Node(a.freq+b.freq,a,b));}
        Map<Character,String> map=new HashMap<>();
        buildMap(pq.poll(),"",map);

        int total = 0; for(int f:freqs) total+=f;
        int fixedBits = (int)Math.ceil(Math.log(chars.length)/Math.log(2));
        int huffBits = 0;
        for(int i=0;i<chars.length;i++) huffBits += freqs[i] * map.get(chars[i]).length();
        int fixedTotal = total * fixedBits;

        System.out.println("Total symbols: " + total);
        System.out.println("Fixed-width bits/symbol: " + fixedBits);
        System.out.println("Fixed-width total bits:  " + fixedTotal);
        System.out.println("Huffman total bits:      " + huffBits);
        // TODO: Print compression ratio as percentage: (huffBits * 100 / fixedTotal)%
        // TODO: Print bits saved: fixedTotal - huffBits
    }

    public static void main(String[] args) {
        HuffmanRatio hr = new HuffmanRatio();
        char[] chars = {'a','b','c','d','e','f'};
        int[]  freqs  = { 45, 13, 12, 16,  9,  5};
        hr.analyze(chars, freqs);
    }
}
